// ---------------------------------------------------------------------------
// cascade_skip macro
// ---------------------------------------------------------------------------

/// Print a skip diagnostic and return early. Never panics.
/// Usage: `cascade_skip!("reason", "CL-NNN")`.
#[allow(unused_macros)]
macro_rules! cascade_skip {
    ($reason:expr, $issue:expr) => {{
        eprintln!(
            "  [cascade_skip] {} — {} (tracking: {})",
            module_path!(),
            $reason,
            $issue
        );
        return;
    }};
}

// ---------------------------------------------------------------------------
// Fixture loading
// ---------------------------------------------------------------------------

fn fixture_path() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("conformance")
        .join("fixtures_graph.json")
}

fn load_fixtures() -> serde_json::Value {
    let path = fixture_path();
    let body = std::fs::read_to_string(&path).unwrap_or_else(|e| {
        panic!("read fixtures_graph.json: {e}. Run scripts/regenerate_jit_fixtures.py")
    });
    serde_json::from_str(&body).expect("parse fixtures_graph.json")
}

fn fixture_by_case<'a>(
    fixtures: &'a serde_json::Value,
    case: &str,
) -> Option<&'a serde_json::Value> {
    fixtures["fixtures"]
        .as_array()?
        .iter()
        .find(|f| f["case"].as_str() == Some(case))
}

