fn grad_vec_f32(data: Vec<f32>) -> Tensor<f32> {
    let n = data.len();
    Tensor::from_storage(TensorStorage::cpu(data), vec![n], true)
        .unwrap()
        .requires_grad_(true)
}

fn grad_mat_f32(data: Vec<f32>, rows: usize, cols: usize) -> Tensor<f32> {
    Tensor::from_storage(TensorStorage::cpu(data), vec![rows, cols], true)
        .unwrap()
        .requires_grad_(true)
}

