/// graph_add_relu_node_count: input -> add(x,x) -> relu -> output.
/// Expected: 3 nodes, 3 values, 1 input, 1 output.
#[test]
fn graph_add_relu_node_count() {
    let fixtures = load_fixtures();
    let fx = fixture_by_case(&fixtures, "graph_add_relu_node_count").expect("fixture missing");
    let expected = &fx["expected"];

    let mut g = IrGraph::new();
    let x = g.add_input(vec![2, 3]);
    let (_, add_outs) = g.add_node(IrOpKind::Add, vec![x, x], vec![vec![2, 3]]);
    let (_, relu_outs) = g.add_node(IrOpKind::Relu, vec![add_outs[0]], vec![vec![2, 3]]);
    g.set_outputs(vec![relu_outs[0]]);

    let expected_nc = expected["node_count"].as_u64().unwrap() as usize;
    let expected_vc = expected["value_count"].as_u64().unwrap() as usize;
    let expected_ic = expected["input_count"].as_u64().unwrap() as usize;
    let expected_oc = expected["output_count"].as_u64().unwrap() as usize;

    assert_eq!(g.node_count(), expected_nc, "node_count mismatch");
    assert_eq!(g.value_count(), expected_vc, "value_count mismatch");
    assert_eq!(g.input_values.len(), expected_ic, "input_count mismatch");
    assert_eq!(g.output_values.len(), expected_oc, "output_count mismatch");

    // Verify op sequence via topological order.
    let order = g.topological_order();
    assert_eq!(order.len(), expected_nc);

    let node_for = |id: IrNodeId| g.nodes.iter().find(|n| n.id == id).unwrap();
    assert!(matches!(node_for(order[0]).op, IrOpKind::Input { .. }));
    assert!(matches!(node_for(order[1]).op, IrOpKind::Add));
    assert!(matches!(node_for(order[2]).op, IrOpKind::Relu));
}

/// graph_two_inputs_mm_sum: A[2,3], B[3,2] -> mm -> sum -> output.
