/// graph_dtype_from_type_name: Dtype::from_type_name recognizes known types.
#[test]
fn graph_dtype_from_type_name_recognizes_primitives() {
    let fixtures = load_fixtures();
    let fx = fixture_by_case(
        &fixtures,
        "graph_dtype_from_type_name_recognizes_primitives",
    )
    .expect("fixture missing");
    let expected = &fx["expected"];

    assert_eq!(
        Dtype::from_type_name("f32"),
        Some(Dtype::F32),
        "f32 should map to F32"
    );
    assert_eq!(
        Dtype::from_type_name("f64"),
        Some(Dtype::F64),
        "f64 should map to F64"
    );
    assert_eq!(
        Dtype::from_type_name("core::primitive::f32"),
        Some(Dtype::F32),
        "core::primitive::f32 should map to F32"
    );
    assert_eq!(
        Dtype::from_type_name("bf16"),
        None,
        "bf16 should return None"
    );
    assert_eq!(Dtype::from_type_name("i32"), None, "i32 should return None");

    // Confirm fixture expectations agree.
    assert_eq!(expected["f32_maps"].as_str().unwrap(), "F32");
    assert_eq!(expected["f64_maps"].as_str().unwrap(), "F64");
    assert_eq!(expected["bf16_maps"].as_str().unwrap(), "None");
}

/// graph_remove_node_decrements_counts: remove_node() updates node/value counts.
#[test]
fn graph_remove_node_decrements_counts() {
    let fixtures = load_fixtures();
    let fx =
        fixture_by_case(&fixtures, "graph_remove_node_decrements_counts").expect("fixture missing");
    let expected = &fx["expected"];

    let mut g = IrGraph::new();
    let x = g.add_input(vec![2]);
    let (add_id, add_outs) = g.add_node(IrOpKind::Add, vec![x, x], vec![vec![2]]);
    let (relu_id, relu_outs) = g.add_node(IrOpKind::Relu, vec![add_outs[0]], vec![vec![2]]);
    g.set_outputs(vec![relu_outs[0]]);

    assert_eq!(
        g.node_count(),
        expected["node_count_before"].as_u64().unwrap() as usize,
        "node_count before remove"
    );
    assert_eq!(
        g.value_count(),
        expected["value_count_before"].as_u64().unwrap() as usize,
        "value_count before remove"
    );

    // Remove relu (the output node).
    g.remove_node(relu_id);
    assert_eq!(
        g.node_count(),
        expected["node_count_after"].as_u64().unwrap() as usize,
        "node_count after remove"
    );
    assert_eq!(
        g.value_count(),
        expected["value_count_after"].as_u64().unwrap() as usize,
        "value_count after remove"
    );
    let output_cleared = expected["output_cleared"].as_bool().unwrap();
    assert_eq!(
        g.output_values.is_empty(),
        output_cleared,
        "output_values cleared state"
    );

    // Suppress unused variable warnings.
    let _ = add_id;
}

