/// symbolic_guard_accepts_varying_batch: guard with symbolic dim 0 accepts multiple batch sizes.
#[test]
fn symbolic_guard_accepts_varying_batch() {
    let fixtures = load_fixtures();
    let fx = fixture_by_case(&fixtures, "symbolic_guard_accepts_varying_batch")
        .expect("fixture missing");
    let expected = &fx["expected"];

    let trace_shape = vec![4usize, 10];
    let sig = ShapeSignature::new().symbolic_dim(0, 0);
    let guard = Guard::new(vec![trace_shape], sig);

    for shape in fx["test_shapes_accept"].as_array().unwrap() {
        let s: Vec<usize> = shape
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap() as usize)
            .collect();
        let result = guard.check(&[s.as_slice()]);
        assert!(
            result.is_ok(),
            "guard should accept shape {:?}, got: {:?}",
            s,
            result.err()
        );
    }

    assert!(expected["all_pass"].as_bool().unwrap());
}

