/// symbolic_reshape_patch_single: compile_symbolic with symbolic batch patches reshape
/// [4,10] -> [-1,10] so the module can run with different batch sizes.
///
/// patch_reshape_for_symbolic_dims is now `pub` (#888); we exercise it end-to-end through
/// compile_symbolic which calls it internally — same as the unit tests in symbolic.rs.
#[test]
fn symbolic_reshape_patch_single() {
    use ferrotorch_core::from_vec;
    use ferrotorch_core::grad_fns::shape::reshape;
    use ferrotorch_jit::symbolic::compile_symbolic;

    let fixtures = load_fixtures();
    let _fx = fixture_by_case(&fixtures, "symbolic_reshape_patch_single").expect("fixture missing");

    // Trace a graph that reshapes its input to its own concrete shape [4, 10].
    // With symbolic dim 0, compile_symbolic should patch this to [-1, 10].
    let example = from_vec(
        (0..40).map(|i| (i as f32 - 20.0) * 0.1).collect::<Vec<_>>(),
        &[4, 10],
    )
    .unwrap()
    .requires_grad_(true);

    let sig = ShapeSignature::new().symbolic_dim(0, 0);
    let compiled = compile_symbolic::<f32, _>(
        |inputs| {
            let shape_isize: Vec<isize> = inputs[0].shape().iter().map(|&d| d as isize).collect();
            let r = reshape(&inputs[0], &shape_isize)?;
            relu(&r)
        },
        &[example],
        sig,
    )
    .unwrap();

    // If the patch worked, we can run with batch=9 (impossible if shape was [4,10]).
    let big = from_vec(
        (0..90).map(|i| (i as f32 - 45.0) * 0.1).collect::<Vec<_>>(),
        &[9, 10],
    )
    .unwrap();
    let out = compiled
        .forward_symbolic(std::slice::from_ref(&big))
        .unwrap();

    assert_eq!(
        out.shape(),
        &[9, 10],
        "reshape patch should allow batch=9 after symbolic tracing"
    );
}

/// symbolic_reshape_patch_ambiguous: when trace shape is [4,4] and dim 0 is symbolic,
/// the reshape target [4,4] has the symbolic value in two positions (ambiguous) — the
/// compiled module should still work for the original batch size but the guard will
/// reject mismatching shapes for the non-patched concrete dim.
///
/// We verify the behaviour indirectly: the guard should still accept [4, 4] since both
/// dims equal the trace-time values, and reject [4, 8] because dim 1 is concrete=4.
#[test]
fn symbolic_reshape_patch_ambiguous() {
    use ferrotorch_core::from_vec;
    use ferrotorch_jit::symbolic::compile_symbolic;

    let _fixtures = load_fixtures();
    let _fx =
        fixture_by_case(&_fixtures, "symbolic_reshape_patch_ambiguous").expect("fixture missing");

    let example = from_vec(vec![0.0f32; 16], &[4, 4])
        .unwrap()
        .requires_grad_(true);

    let sig = ShapeSignature::new().symbolic_dim(0, 0);
    let compiled = compile_symbolic::<f32, _>(|inputs| relu(&inputs[0]), &[example], sig).unwrap();

    // [4, 4] must be accepted (same as trace shape).
    let same = from_vec(vec![0.0f32; 16], &[4, 4]).unwrap();
    assert!(
        compiled
            .forward_symbolic(std::slice::from_ref(&same))
            .is_ok(),
        "guard must accept trace-time shape [4,4]"
    );

    // [8, 4] must be accepted (batch varies, feature dim matches).
    let bigger_batch = from_vec(vec![0.0f32; 32], &[8, 4]).unwrap();
    assert!(
        compiled
            .forward_symbolic(std::slice::from_ref(&bigger_batch))
            .is_ok(),
        "guard must accept [8,4] since dim 0 is symbolic"
    );

    // [4, 8] must be rejected (feature dim=4 is concrete, runtime=8 mismatches).
    let wrong_feat = from_vec(vec![0.0f32; 32], &[4, 8]).unwrap();
    let result = compiled.forward_symbolic(std::slice::from_ref(&wrong_feat));
    assert!(
        result.is_err(),
        "guard must reject [4,8] since dim 1 is concrete=4"
    );
}

