/// codegen_ir_neg_single_loop: Neg lowers to 1 flat loop.
#[test]
fn codegen_ir_neg_single_loop() {
    let fixtures = load_fixtures();
    let fx = fixture_by_case(&fixtures, "codegen_ir_neg_single_loop").expect("fixture missing");
    let expected = &fx["expected"];

    let loops = lower_to_loops(&[IrOpKind::Neg], &["in0"], "out", 8);

    assert_eq!(
        loops.len(),
        expected["stmt_count"].as_u64().unwrap() as usize,
        "stmt_count"
    );
    match &loops[0] {
        LoopIR::Loop {
            var,
            start,
            end,
            body,
        } => {
            assert_eq!(var, "i");
            assert_eq!(*start, Expr::int(expected["loop_start"].as_i64().unwrap()));
            assert_eq!(*end, Expr::int(expected["loop_end"].as_i64().unwrap()));
            assert_eq!(
                body.len(),
                expected["body_count"].as_u64().unwrap() as usize
            );
            assert!(
                matches!(body[0], LoopIR::Store { .. }),
                "body[0] must be Store"
            );
        }
        other => panic!("expected Loop, got {other:?}"),
    }
}

