/// codegen_ir_op_classification: is_unary_elementwise / is_binary / is_reduction / is_elementwise.
#[test]
fn codegen_ir_op_classification() {
    // Unary elementwise
    for op in [
        IrOpKind::Neg,
        IrOpKind::Exp,
        IrOpKind::Log,
        IrOpKind::Sqrt,
        IrOpKind::Abs,
        IrOpKind::Sigmoid,
        IrOpKind::Tanh,
        IrOpKind::Relu,
        IrOpKind::Gelu,
        IrOpKind::Silu,
    ] {
        assert!(
            is_unary_elementwise(&op),
            "{op:?} must be unary elementwise"
        );
        assert!(
            ir_op_to_unary(&op).is_some(),
            "{op:?} must map via ir_op_to_unary"
        );
        assert!(is_elementwise(&op), "{op:?} must be elementwise");
        assert!(!is_reduction(&op), "{op:?} must not be reduction");
    }

    // Pow is unary elementwise too (parameterized)
    assert!(
        is_unary_elementwise(&IrOpKind::Pow { exponent: 2.0 }),
        "Pow must be unary elementwise"
    );

    // Binary elementwise
    for op in [IrOpKind::Add, IrOpKind::Sub, IrOpKind::Mul, IrOpKind::Div] {
        assert!(
            is_binary_elementwise(&op),
            "{op:?} must be binary elementwise"
        );
        assert!(
            ir_op_to_binary(&op).is_some(),
            "{op:?} must map via ir_op_to_binary"
        );
        assert!(is_elementwise(&op), "{op:?} must be elementwise");
        assert!(!is_reduction(&op), "{op:?} must not be reduction");
    }

    // Reductions
    for op in [IrOpKind::Sum, IrOpKind::Mean, IrOpKind::Prod] {
        assert!(is_reduction(&op), "{op:?} must be reduction");
        assert!(!is_unary_elementwise(&op), "{op:?} must not be unary");
        assert!(!is_binary_elementwise(&op), "{op:?} must not be binary");
    }

    // Non-elementwise
    for op in [IrOpKind::Matmul, IrOpKind::Mm] {
        assert!(!is_elementwise(&op), "{op:?} must not be elementwise");
        assert!(!is_reduction(&op), "{op:?} must not be reduction");
    }
}

/// codegen_ir_apply_binary_op_expr: apply_binary_op_expr produces a BinOp.
#[test]
fn codegen_ir_apply_binary_op_expr() {
    let lhs = Expr::var("a");
    let rhs = Expr::var("b");

    for (op, expected_kind) in [
        (IrOpKind::Add, BinOpKind::Add),
        (IrOpKind::Sub, BinOpKind::Sub),
        (IrOpKind::Mul, BinOpKind::Mul),
        (IrOpKind::Div, BinOpKind::Div),
    ] {
        let result = apply_binary_op_expr(lhs.clone(), rhs.clone(), &op);
        assert!(result.is_some(), "{op:?} should produce Some(expr)");
        match result.unwrap() {
            Expr::BinOp { op: actual_op, .. } => {
                assert_eq!(actual_op, expected_kind, "BinOpKind mismatch for {op:?}");
            }
            other => panic!("{op:?} must produce BinOp, got {other:?}"),
        }
    }

    // Non-binary ops should return None.
    assert!(
        apply_binary_op_expr(lhs.clone(), rhs.clone(), &IrOpKind::Neg).is_none(),
        "Neg should not produce binary expr"
    );
}
